    60→        throw new Error(`Template file not found: ${clientTemplate}`);
    61→      }
    62→
    63→      // always reload the index.html file from disk incase it changes
    64→      let template = await fs.promises.readFile(clientTemplate, "utf-8");
    65→      template = template.replace(
    66→        `src="/src/main.tsx"`,
    67→        `src="/src/main.tsx?v=${nanoid()}"`,
