    59→  // Calculate for each package type
    60→  for (const [packageType, config] of Object.entries(packages)) {
    61→    const packageData = config as any;
    62→    
    63→    // Calculate all discounts even for unavailable packages for display purposes
    64→    let discount = packageData.discount;
    65→    
    66→    if (packageData.dynamicDiscount) {
    67→        // Используем только sessionCount для расчета стоимости
    68→        // baseCost += price * selectedService.quantity * (selectedService.sessionCount || 10);
    69→      discount = Math.max(discount, packageData.dynamicDiscount);
    70→    }
    71→
    72→    // Calculate certificate discount using configurable fixed amount
    73→    const certificateDiscountAmount = calculatorSettings?.certificateDiscountAmount || 3000;
    74→    const certificateMinAmount = calculatorSettings?.certificateMinCourseAmount || 25000;
    75→    const certificateDiscount = params.usedCertificate && baseCost >= certificateMinAmount ? certificateDiscountAmount : 0;
    76→    
    77→
    78→    
