   110→    const actualDiscounts = packageDiscount + certificateDiscount + additionalDiscount + correctionDiscount;
   111→    const totalSavings = actualDiscounts; // Only actual discounts, not gifts
   112→    const finalCost = baseCost - actualDiscounts; // Actual cost without gift sessions
   113→
   114→    // All packages are available for selection - payment constraints will be applied when selected
   115→    const minDownPayment = Math.max(
   116→      packageData.minDownPayment || 0,
