   123→
   124→    // Check if package meets minimum cost requirement
   125→    const isAvailable = baseCost >= packageData.minCost;
   126→    const shortage = packageData.minCost - baseCost;
   127→    const unavailableReason = !isAvailable ? `Не хватает ${shortage.toLocaleString()} ₽ (минимум: ${packageData.minCost.toLocaleString()} ₽)` : '';
   128→
   129→    results[packageType] = {
   130→      isAvailable,
   131→      unavailableReason,
   132→      finalCost,
   133→      totalSavings,
   134→      monthlyPayment: isAvailable ? monthlyPayment : 0,
   135→      appliedDiscounts: [
   136→        { type: 'package', amount: packageDiscount },
   137→        ...(qualifiesForBulkDiscount && additionalDiscount > 0 ? [{ type: 'bulk', amount: additionalDiscount }] : []),
   138→        ...(certificateDiscount > 0 ? [{ type: 'certificate', amount: certificateDiscount }] : []),
   139→        ...(correctionDiscount > 0 ? [{ type: 'correction', amount: correctionDiscount }] : []),
   140→        ...(giftSessionValue > 0 ? [{ type: 'gift_sessions', amount: giftSessionValue }] : [])
   141→      ]
   142→    };
   143→  }
   144→
   145→  return {
   146→    baseCost,
   147→    packages: results,
   148→    totalProcedures,
   149→    freeZonesValue: params.freeZonesValue || 0
   150→  };
   151→}

