   159→/* ── Progress dots on slider ─────────────────────────────────────── */
   160→function TrackMarkers({ min, max, dp }: { min: number; max: number; dp: number }) {
   161→  const range = max - min;
   162→  if (range <= 0) return null;
   163→  return (
   164→    <div style={{ position: "relative", height: 14, marginTop: 3 }}>
   165→      {PRIVS.filter(p => !p.fp && p.dpT > min && p.dpT < max).map(p => {
   166→        const pct = ((p.dpT - min) / range) * 100;
   167→        const ok  = dp >= p.dpT;
   168→        return (
   169→          <div key={p.id} style={{ position: "absolute", left: `${pct}%`, transform: "translateX(-50%)", display: "flex", flexDirection: "column", alignItems: "center", gap: 1 }}>
   170→            <div style={{ width: 1, height: 4, background: ok ? "rgba(255,255,255,0.4)" : "rgba(255,255,255,0.1)", transition: "background 0.3s" }} />
   171→            <div style={{ width: 4, height: 4, borderRadius: "50%", background: ok ? p.color : "rgba(255,255,255,0.12)", boxShadow: ok ? `0 0 6px ${p.color}88` : "none", transition: "all 0.3s" }} />
   172→          </div>
   173→        );
   174→      })}
   175→    </div>
   176→  );
   177→}
