   179→/* ══════════════════════════════════════════════════════════════════════ */
   180→/* ── Continuous discount progress (0-100) ───────────────────────────── */
   181→// Tiers: 20%→0, 25%→20, 30%→40, 35%→60, 40%→80, 46%→100
   182→function getBarProgress(proc: number): number {
   183→  if (proc >= 20) return 100;
   184→  if (proc >= 15) return 80 + Math.min(1, (proc - 15) / 5) * 20;
   185→  if (proc >= 10) return 60 + Math.min(1, (proc - 10) / 5) * 20;
   186→  if (proc >= 8)  return 40 + Math.min(1, (proc - 8)  / 2) * 20;
   187→  if (proc >= 5)  return 20 + Math.min(1, (proc - 5)  / 3) * 20;
   188→  if (proc >= 1)  return Math.min(1, proc / 5) * 20;
   189→  return 0;
   190→}
